     1ŌåÆ#!/usr/bin/env bun
     2ŌåÆ/**
     3ŌåÆ * ExplicitRatingCapture.hook.ts - Capture Explicit User Ratings (UserPromptSubmit)
     4ŌåÆ *
     5ŌåÆ * PURPOSE:
     6ŌåÆ * Detects when the user explicitly rates a response with a number 1-10.
     7ŌåÆ * This is the primary feedback mechanism for the rating/sentiment system.
     8ŌåÆ * Low ratings trigger automatic learning capture for improvement analysis.
     9ŌåÆ *
    10ŌåÆ * TRIGGER: UserPromptSubmit
    11ŌåÆ *
    12ŌåÆ * INPUT:
    13ŌåÆ * - prompt: User's message text
    14ŌåÆ * - session_id: Current session identifier
    15ŌåÆ * - transcript_path: Path to conversation transcript
    16ŌåÆ *
    17ŌåÆ * OUTPUT:
    18ŌåÆ * - stdout: None (no context injection)
    19ŌåÆ * - exit(0): Normal completion
    20ŌåÆ *
    21ŌåÆ * SIDE EFFECTS:
    22ŌåÆ * - Writes to: MEMORY/LEARNING/SIGNALS/ratings.jsonl
    23ŌåÆ * - Writes to: MEMORY/LEARNING/<category>/<YYYY-MM>/*.md (for low ratings)
    24ŌåÆ * - Triggers: TrendingAnalysis.ts update (fire-and-forget)
    25ŌåÆ *
    26ŌåÆ * INTER-HOOK RELATIONSHIPS:
    27ŌåÆ * - DEPENDS ON: None
    28ŌåÆ * - COORDINATES WITH: ImplicitSentimentCapture (shares ratings.jsonl)
    29ŌåÆ * - MUST RUN BEFORE: ImplicitSentimentCapture (explicit takes priority)
    30ŌåÆ * - MUST RUN AFTER: None
    31ŌåÆ *
    32ŌåÆ * COORDINATION PROTOCOL:
    33ŌåÆ * Both ExplicitRatingCapture and ImplicitSentimentCapture write to ratings.jsonl.
    34ŌåÆ * ImplicitSentimentCapture checks isExplicitRating() first and defers if true.
    35ŌåÆ * This hook runs FIRST to capture explicit "8 - great work" style ratings.
    36ŌåÆ *
    37ŌåÆ * ERROR HANDLING:
    38ŌåÆ * - Invalid input: Exits gracefully
    39ŌåÆ * - Write failures: Logged to stderr, exits gracefully
    40ŌåÆ *
    41ŌåÆ * PERFORMANCE:
    42ŌåÆ * - Non-blocking: Yes
    43ŌåÆ * - Typical execution: <50ms
    44ŌåÆ * - No external API calls
    45ŌåÆ *
    46ŌåÆ * RATING PATTERNS:
    47ŌåÆ * - "7" ŌåÆ rating 7, no comment
    48ŌåÆ * - "8 - good work" ŌåÆ rating 8, comment "good work"
    49ŌåÆ * - "6: needs improvement" ŌåÆ rating 6, comment "needs improvement"
    50ŌåÆ * - "9 excellent" ŌåÆ rating 9, comment "excellent"
    51ŌåÆ * - "10!" ŌåÆ rating 10, no comment
    52ŌåÆ *
    53ŌåÆ * NON-RATING PATTERNS (ignored):
    54ŌåÆ * - "3 items" ŌåÆ Not a rating (followed by unit)
    55ŌåÆ * - "5 things to fix" ŌåÆ Not a rating (sentence continuation)
    56ŌåÆ */
    57ŌåÆ
    58ŌåÆimport { appendFileSync, mkdirSync, existsSync, readFileSync, writeFileSync } from 'fs';
    59ŌåÆimport { join } from 'path';
    60ŌåÆimport { getLearningCategory } from './lib/learning-utils';
    61ŌåÆimport { getPrincipalName } from './lib/identity';
    62ŌåÆimport { getISOTimestamp, getPSTComponents } from './lib/time';
    63ŌåÆimport { captureFailure } from '../skills/PAI/Tools/FailureCapture';
    64ŌåÆ
    65ŌåÆinterface HookInput {
    66ŌåÆ  session_id: string;
    67ŌåÆ  prompt: string;
    68ŌåÆ  transcript_path: string;
    69ŌåÆ  hook_event_name: string;
    70ŌåÆ}
    71ŌåÆ
    72ŌåÆinterface RatingEntry {
    73ŌåÆ  timestamp: string;
    74ŌåÆ  rating: number;
    75ŌåÆ  comment?: string;
    76ŌåÆ  session_id: string;
    77ŌåÆ}
    78ŌåÆ
    79ŌåÆ/**
    80ŌåÆ * Read stdin with timeout
    81ŌåÆ */
    82ŌåÆasync function readStdinWithTimeout(timeout: number = 5000): Promise<string> {
    83ŌåÆ  return new Promise((resolve, reject) => {
    84ŌåÆ    let data = '';
    85ŌåÆ    const timer = setTimeout(() => reject(new Error('Timeout')), timeout);
    86ŌåÆ    process.stdin.on('data', (chunk) => { data += chunk.toString(); });
    87ŌåÆ    process.stdin.on('end', () => { clearTimeout(timer); resolve(data); });
    88ŌåÆ    process.stdin.on('error', (err) => { clearTimeout(timer); reject(err); });
    89ŌåÆ  });
    90ŌåÆ}
    91ŌåÆ
    92ŌåÆ/**
    93ŌåÆ * CRITICAL: Precise rating detection
    94ŌåÆ *
    95ŌåÆ * Must match:
    96ŌåÆ * - "7" (single number)
    97ŌåÆ * - "8 - good work" (number + dash + comment)
    98ŌåÆ * - "6: needs work" (number + colon + comment)
    99ŌåÆ * - "9 excellent" (number + space + comment)
   100ŌåÆ *
   101ŌåÆ * Must NOT match:
   102ŌåÆ * - "I have 7 items" (number in sentence)
   103ŌåÆ * - "do step 7" (contextual number)
   104ŌåÆ * - "7th thing" (ordinal)
   105ŌåÆ */
   106ŌåÆfunction parseRating(prompt: string): { rating: number; comment?: string } | null {
   107ŌåÆ  const trimmed = prompt.trim();
   108ŌåÆ
   109ŌåÆ  // Pattern: Start with single digit (1-10), optionally followed by separator and comment
   110ŌåÆ  const ratingPattern = /^(10|[1-9])(?:\s*[-:]\s*|\s+)?(.*)$/;
   111ŌåÆ
   112ŌåÆ  const match = trimmed.match(ratingPattern);
   113ŌåÆ  if (!match) return null;
   114ŌåÆ
   115ŌåÆ  const rating = parseInt(match[1], 10);
   116ŌåÆ  const comment = match[2]?.trim() || undefined;
   117ŌåÆ
   118ŌåÆ  if (rating < 1 || rating > 10) return null;
   119ŌåÆ
   120ŌåÆ  // Reject if comment starts with common words that indicate a sentence
   121ŌåÆ  if (comment) {
   122ŌåÆ    const sentenceStarters = /^(items?|things?|steps?|files?|lines?|bugs?|issues?|errors?|times?|minutes?|hours?|days?|seconds?|percent|%|th\b|st\b|nd\b|rd\b|of\b|in\b|at\b|to\b|the\b|a\b|an\b)/i;
   123ŌåÆ    if (sentenceStarters.test(comment)) {
   124ŌåÆ      return null;
   125ŌåÆ    }
   126ŌåÆ  }
   127ŌåÆ
   128ŌåÆ  return { rating, comment };
   129ŌåÆ}
   130ŌåÆ
   131ŌåÆ/**
   132ŌåÆ * Write rating to ratings.jsonl
   133ŌåÆ * NOTE: Ratings are now stored in LEARNING/SIGNALS/ (consolidated from separate SIGNALS/)
   134ŌåÆ */
   135ŌåÆfunction writeRating(entry: RatingEntry): void {
   136ŌåÆ  const baseDir = process.env.PAI_DIR || join(process.env.HOME!, '.claude');
   137ŌåÆ  const signalsDir = join(baseDir, 'MEMORY', 'LEARNING', 'SIGNALS');
   138ŌåÆ  const ratingsFile = join(signalsDir, 'ratings.jsonl');
   139ŌåÆ
   140ŌåÆ  if (!existsSync(signalsDir)) {
   141ŌåÆ    mkdirSync(signalsDir, { recursive: true });
   142ŌåÆ  }
   143ŌåÆ
   144ŌåÆ  const jsonLine = JSON.stringify(entry) + '\n';
   145ŌåÆ  appendFileSync(ratingsFile, jsonLine, 'utf-8');
   146ŌåÆ
   147ŌåÆ  console.error(`[ExplicitRatingCapture] Wrote rating ${entry.rating} to ${ratingsFile}`);
   148ŌåÆ}
   149ŌåÆ
   150ŌåÆ/**
   151ŌåÆ * Extract last response summary from transcript for learning context
   152ŌåÆ */
   153ŌåÆfunction getLastResponseSummary(transcriptPath: string): string {
   154ŌåÆ  try {
   155ŌåÆ    if (!transcriptPath || !existsSync(transcriptPath)) return '';
   156ŌåÆ
   157ŌåÆ    const content = readFileSync(transcriptPath, 'utf-8');
   158ŌåÆ    const lines = content.trim().split('\n');
   159ŌåÆ
   160ŌåÆ    let lastAssistant = '';
   161ŌåÆ    for (const line of lines) {
   162ŌåÆ      try {
   163ŌåÆ        const entry = JSON.parse(line);
   164ŌåÆ        if (entry.type === 'assistant' && entry.message?.content) {
   165ŌåÆ          const text = typeof entry.message.content === 'string'
   166ŌåÆ            ? entry.message.content
   167ŌåÆ            : Array.isArray(entry.message.content)
   168ŌåÆ              ? entry.message.content.filter((c: any) => c.type === 'text').map((c: any) => c.text).join(' ')
   169ŌåÆ              : '';
   170ŌåÆ          if (text) lastAssistant = text;
   171ŌåÆ        }
   172ŌåÆ      } catch { /* skip invalid lines */ }
   173ŌåÆ    }
   174ŌåÆ
   175ŌåÆ    const summaryMatch = lastAssistant.match(/SUMMARY:\s*([^\n]+)/i);
   176ŌåÆ    return summaryMatch ? summaryMatch[1].trim() : lastAssistant.slice(0, 500);
   177ŌåÆ  } catch {
   178ŌåÆ    return '';
   179ŌåÆ  }
   180ŌåÆ}
   181ŌåÆ
   182ŌåÆ/**
   183ŌåÆ * Capture low rating as learning opportunity
   184ŌåÆ */
   185ŌåÆfunction captureLowRatingLearning(rating: number, comment: string | undefined, responseContext: string): void {
   186ŌåÆ  if (rating >= 6) return;
   187ŌåÆ
   188ŌåÆ  const baseDir = process.env.PAI_DIR || join(process.env.HOME!, '.claude');
   189ŌåÆ  const { year, month, day, hours, minutes, seconds } = getPSTComponents();
   190ŌåÆ
   191ŌåÆ  const yearMonth = `${year}-${month}`;
   192ŌåÆ  const category = getLearningCategory(responseContext, comment);
   193ŌåÆ  const learningsDir = join(baseDir, 'MEMORY', 'LEARNING', category, yearMonth);
   194ŌåÆ
   195ŌåÆ  if (!existsSync(learningsDir)) {
   196ŌåÆ    mkdirSync(learningsDir, { recursive: true });
   197ŌåÆ  }
   198ŌåÆ
   199ŌåÆ  const filename = `${year}-${month}-${day}-${hours}${minutes}${seconds}_LEARNING_low-rating-${rating}.md`;
   200ŌåÆ  const filepath = join(learningsDir, filename);
   201ŌåÆ
   202ŌåÆ  const content = `---
   203ŌåÆcapture_type: LEARNING
   204ŌåÆtimestamp: ${year}-${month}-${day} ${hours}:${minutes}:${seconds} PST
   205ŌåÆrating: ${rating}
   206ŌåÆauto_captured: true
   207ŌåÆtags: [low-rating, improvement-opportunity]
   208ŌåÆ---
   209ŌåÆ
   210ŌåÆ# Low Rating Captured: ${rating}/10
   211ŌåÆ
   212ŌåÆ**Date:** ${year}-${month}-${day}
   213ŌåÆ**Rating:** ${rating}/10
   214ŌåÆ${comment ? `**Feedback:** ${comment}` : ''}
   215ŌåÆ
   216ŌåÆ---
   217ŌåÆ
   218ŌåÆ## Response Context
   219ŌåÆ
   220ŌåÆ${responseContext || 'No response context available'}
   221ŌåÆ
   222ŌåÆ---
   223ŌåÆ
   224ŌåÆ## Improvement Notes
   225ŌåÆ
   226ŌåÆThis response was rated ${rating}/10 by ${getPrincipalName()}. Use this as an improvement opportunity.
   227ŌåÆ
   228ŌåÆ${comment ? `**${getPrincipalName()}'s feedback:** ${comment}` : ''}
   229ŌåÆ
   230ŌåÆ---
   231ŌåÆ`;
   232ŌåÆ
   233ŌåÆ  writeFileSync(filepath, content, 'utf-8');
   234ŌåÆ  console.error(`[ExplicitRatingCapture] Captured low rating learning to ${filepath}`);
   235ŌåÆ}
   236ŌåÆ
   237ŌåÆasync function main() {
   238ŌåÆ  try {
   239ŌåÆ    console.error('[ExplicitRatingCapture] Hook started');
   240ŌåÆ    const input = await readStdinWithTimeout();
   241ŌåÆ    const data: HookInput = JSON.parse(input);
   242ŌåÆ    const prompt = data.prompt || '';
   243ŌåÆ
   244ŌåÆ    const result = parseRating(prompt);
   245ŌåÆ
   246ŌåÆ    if (!result) {
   247ŌåÆ      console.error('[ExplicitRatingCapture] Not a rating, exiting');
   248ŌåÆ      process.exit(0);
   249ŌåÆ    }
   250ŌåÆ
   251ŌåÆ    console.error(`[ExplicitRatingCapture] Detected rating: ${result.rating}${result.comment ? ` - ${result.comment}` : ''}`);
   252ŌåÆ
   253ŌåÆ    const entry: RatingEntry = {
   254ŌåÆ      timestamp: getISOTimestamp(),
   255ŌåÆ      rating: result.rating,
   256ŌåÆ      session_id: data.session_id,
   257ŌåÆ    };
   258ŌåÆ    if (result.comment) {
   259ŌåÆ      entry.comment = result.comment;
   260ŌåÆ    }
   261ŌåÆ
   262ŌåÆ    writeRating(entry);
   263ŌåÆ
   264ŌåÆ    // Update trending analysis cache (fire-and-forget, don't block)
   265ŌåÆ    const baseDir = process.env.PAI_DIR || join(process.env.HOME!, '.claude');
   266ŌåÆ    const trendingScript = join(baseDir, 'tools', 'TrendingAnalysis.ts');
   267ŌåÆ    if (existsSync(trendingScript)) {
   268ŌåÆ      Bun.spawn(['bun', trendingScript, '--force'], {
   269ŌåÆ        stdout: 'ignore',
   270ŌåÆ        stderr: 'ignore'
   271ŌåÆ      });
   272ŌåÆ      console.error('[ExplicitRatingCapture] Triggered TrendingAnalysis update');
   273ŌåÆ    }
   274ŌåÆ
   275ŌåÆ    if (result.rating < 6) {
   276ŌåÆ      const responseContext = getLastResponseSummary(data.transcript_path);
   277ŌåÆ      captureLowRatingLearning(result.rating, result.comment, responseContext);
   278ŌåÆ
   279ŌåÆ      // For ratings 1-3, also create full failure capture
   280ŌåÆ      if (result.rating <= 3) {
   281ŌåÆ        try {
   282ŌåÆ          await captureFailure({
   283ŌåÆ            transcriptPath: data.transcript_path,
   284ŌåÆ            rating: result.rating,
   285ŌåÆ            sentimentSummary: result.comment || `Explicit low rating: ${result.rating}/10`,
   286ŌåÆ            detailedContext: responseContext,
   287ŌåÆ            sessionId: data.session_id,
   288ŌåÆ          });
   289ŌåÆ          console.error(`[ExplicitRatingCapture] Created full failure capture for rating ${result.rating}`);
   290ŌåÆ        } catch (err) {
   291ŌåÆ          console.error(`[ExplicitRatingCapture] Error creating failure capture: ${err}`);
   292ŌåÆ        }
   293ŌåÆ      }
   294ŌåÆ    }
   295ŌåÆ
   296ŌåÆ    console.error('[ExplicitRatingCapture] Done');
   297ŌåÆ    process.exit(0);
   298ŌåÆ  } catch (err) {
   299ŌåÆ    console.error(`[ExplicitRatingCapture] Error: ${err}`);
   300ŌåÆ    process.exit(0);
   301ŌåÆ  }
   302ŌåÆ}
   303ŌåÆ
   304ŌåÆmain();
   305ŌåÆ

