     1ŌåÆ#!/usr/bin/env bun
     2ŌåÆ/**
     3ŌåÆ * CheckVersion.hook.ts - Check for Claude Code Updates (SessionStart)
     4ŌåÆ *
     5ŌåÆ * PURPOSE:
     6ŌåÆ * Compares the installed Claude Code version against the latest available on npm.
     7ŌåÆ * If an update is available, displays a notification to stderr. This keeps the
     8ŌåÆ * system current without interrupting workflow.
     9ŌåÆ *
    10ŌåÆ * TRIGGER: SessionStart
    11ŌåÆ *
    12ŌåÆ * INPUT:
    13ŌåÆ * - None (reads version info from CLI and npm)
    14ŌåÆ *
    15ŌåÆ * OUTPUT:
    16ŌåÆ * - stdout: None
    17ŌåÆ * - stderr: Update notification if newer version available
    18ŌåÆ * - exit(0): Always (non-blocking)
    19ŌåÆ *
    20ŌåÆ * SIDE EFFECTS:
    21ŌåÆ * - Network request to npm registry (brief)
    22ŌåÆ * - Spawns two child processes for version checks
    23ŌåÆ *
    24ŌåÆ * INTER-HOOK RELATIONSHIPS:
    25ŌåÆ * - DEPENDS ON: None
    26ŌåÆ * - COORDINATES WITH: None (fully independent)
    27ŌåÆ * - MUST RUN BEFORE: None (informational only)
    28ŌåÆ * - MUST RUN AFTER: None
    29ŌåÆ *
    30ŌåÆ * ERROR HANDLING:
    31ŌåÆ * - Network failures: Silent exit (doesn't block session)
    32ŌåÆ * - Parse failures: Returns 'unknown', silent exit
    33ŌåÆ *
    34ŌåÆ * PERFORMANCE:
    35ŌåÆ * - Non-blocking: Yes
    36ŌåÆ * - Typical execution: <500ms
    37ŌåÆ * - Skipped for subagents: Yes
    38ŌåÆ */
    39ŌåÆ
    40ŌåÆasync function getCurrentVersion(): Promise<string> {
    41ŌåÆ  try {
    42ŌåÆ    const proc = Bun.spawn(['claude', '--version'], {
    43ŌåÆ      stdout: 'pipe',
    44ŌåÆ      stderr: 'pipe'
    45ŌåÆ    });
    46ŌåÆ    const output = await new Response(proc.stdout).text();
    47ŌåÆ    const match = output.match(/(\d+\.\d+\.\d+)/);
    48ŌåÆ    return match ? match[1] : 'unknown';
    49ŌåÆ  } catch {
    50ŌåÆ    return 'unknown';
    51ŌåÆ  }
    52ŌåÆ}
    53ŌåÆ
    54ŌåÆasync function getLatestVersion(): Promise<string> {
    55ŌåÆ  try {
    56ŌåÆ    const proc = Bun.spawn(['npm', 'view', '@anthropic-ai/claude-code', 'version'], {
    57ŌåÆ      stdout: 'pipe',
    58ŌåÆ      stderr: 'pipe'
    59ŌåÆ    });
    60ŌåÆ    const output = await new Response(proc.stdout).text();
    61ŌåÆ    return output.trim() || 'unknown';
    62ŌåÆ  } catch {
    63ŌåÆ    return 'unknown';
    64ŌåÆ  }
    65ŌåÆ}
    66ŌåÆ
    67ŌåÆasync function main() {
    68ŌåÆ  try {
    69ŌåÆ    // Skip for subagents
    70ŌåÆ    const claudeProjectDir = process.env.CLAUDE_PROJECT_DIR || '';
    71ŌåÆ    const isSubagent = claudeProjectDir.includes('/.claude/Agents/') ||
    72ŌåÆ                      process.env.CLAUDE_AGENT_TYPE !== undefined;
    73ŌåÆ
    74ŌåÆ    if (isSubagent) {
    75ŌåÆ      process.exit(0);
    76ŌåÆ    }
    77ŌåÆ
    78ŌåÆ    const [currentVersion, latestVersion] = await Promise.all([
    79ŌåÆ      getCurrentVersion(),
    80ŌåÆ      getLatestVersion()
    81ŌåÆ    ]);
    82ŌåÆ
    83ŌåÆ    if (currentVersion !== 'unknown' && latestVersion !== 'unknown' && currentVersion !== latestVersion) {
    84ŌåÆ      console.error(`­¤ÆĪ Update available: CC ${currentVersion} ŌåÆ ${latestVersion}`);
    85ŌåÆ    }
    86ŌåÆ
    87ŌåÆ    process.exit(0);
    88ŌåÆ  } catch {
    89ŌåÆ    process.exit(0);
    90ŌåÆ  }
    91ŌåÆ}
    92ŌåÆ
    93ŌåÆmain();
    94ŌåÆ

