     1ŌåÆ#!/usr/bin/env bun
     2ŌåÆ/**
     3ŌåÆ * AutoWorkCreation.hook.ts - Session/Task Management (UserPromptSubmit)
     4ŌåÆ *
     5ŌåÆ * PURPOSE:
     6ŌåÆ * Creates and manages the session/task hierarchy for each Claude Code session.
     7ŌåÆ * - SESSION: One directory per Claude Code session (the primitive)
     8ŌåÆ * - TASK: Subdirectories for distinct work items within a session
     9ŌåÆ *
    10ŌåÆ * Each task has its own algorithm execution context (ISC.json, THREAD.md).
    11ŌåÆ *
    12ŌåÆ * TRIGGER: UserPromptSubmit
    13ŌåÆ *
    14ŌåÆ * STRUCTURE CREATED:
    15ŌåÆ * WORK/{timestamp}_{session-title}/
    16ŌåÆ * Ōö£ŌöĆŌöĆ META.yaml                    # Session metadata
    17ŌåÆ * Ōö£ŌöĆŌöĆ tasks/
    18ŌåÆ * Ōöé   Ōö£ŌöĆŌöĆ 001_{task-slug}/
    19ŌåÆ * Ōöé   Ōöé   Ōö£ŌöĆŌöĆ ISC.json             # Task's Ideal State Criteria
    20ŌåÆ * Ōöé   Ōöé   ŌööŌöĆŌöĆ THREAD.md            # Task's algorithm log (includes metadata in frontmatter)
    21ŌåÆ * Ōöé   ŌööŌöĆŌöĆ current -> 001_...       # Symlink to active task
    22ŌåÆ * ŌööŌöĆŌöĆ scratch/                     # Temporary files
    23ŌåÆ */
    24ŌåÆ
    25ŌåÆimport { mkdirSync, existsSync, readFileSync, writeFileSync, symlinkSync, unlinkSync, lstatSync } from 'fs';
    26ŌåÆimport { join } from 'path';
    27ŌåÆimport { getPSTComponents, getISOTimestamp } from './lib/time';
    28ŌåÆimport { inference } from '../skills/PAI/Tools/Inference';
    29ŌåÆ
    30ŌåÆinterface HookInput {
    31ŌåÆ  session_id: string;
    32ŌåÆ  prompt?: string;
    33ŌåÆ  user_prompt?: string;
    34ŌåÆ}
    35ŌåÆ
    36ŌåÆinterface CurrentWork {
    37ŌåÆ  session_id: string;
    38ŌåÆ  session_dir: string;
    39ŌåÆ  current_task: string;
    40ŌåÆ  task_count: number;
    41ŌåÆ  created_at: string;
    42ŌåÆ}
    43ŌåÆ
    44ŌåÆinterface PromptClassification {
    45ŌåÆ  type: 'work' | 'question' | 'conversational';
    46ŌåÆ  title: string;
    47ŌåÆ  effort: 'TRIVIAL' | 'QUICK' | 'STANDARD' | 'THOROUGH';
    48ŌåÆ  is_new_topic: boolean;
    49ŌåÆ}
