   234ŌåÆasync function classifyPrompt(prompt: string, hasExistingSession: boolean): Promise<PromptClassification> {
   235ŌåÆ  const trimmed = prompt.trim();
   236ŌåÆ
   237ŌåÆ  // Quick heuristics
   238ŌåÆ  if (trimmed.length < 15 && /^(yes|no|ok|okay|thanks|proceed|continue|go ahead|sure|got it)$/i.test(trimmed)) {
   239ŌåÆ    return { type: 'conversational', title: '', effort: 'TRIVIAL', is_new_topic: false };
   240ŌåÆ  }
   241ŌåÆ
   242ŌåÆ  // Use inference for classification
   243ŌåÆ  try {
   244ŌåÆ    const contextNote = hasExistingSession
   245ŌåÆ      ? '\n\nNOTE: There is an existing session with prior tasks. Consider if this is a continuation or new topic.'
   246ŌåÆ      : '\n\nNOTE: This is the first prompt in a new session. is_new_topic should be true.';
   247ŌåÆ
   248ŌåÆ    const result = await inference({
   249ŌåÆ      systemPrompt: CLASSIFICATION_PROMPT + contextNote,
   250ŌåÆ      userPrompt: prompt,
   251ŌåÆ      expectJson: true,
   252ŌåÆ      timeout: 10000,
   253ŌåÆ      level: 'fast',
   254ŌåÆ    });
   255ŌåÆ
   256ŌåÆ    if (result.success && result.parsed) {
   257ŌåÆ      const parsed = result.parsed as PromptClassification;
   258ŌåÆ      return {
   259ŌåÆ        type: parsed.type || 'work',
   260ŌåÆ        title: parsed.title || prompt.substring(0, 50),
   261ŌåÆ        effort: parsed.effort || 'STANDARD',
   262ŌåÆ        is_new_topic: hasExistingSession ? (parsed.is_new_topic ?? false) : true,
   263ŌåÆ      };
   264ŌåÆ    }
   265ŌåÆ  } catch (err) {
   266ŌåÆ    console.error(`[AutoWork] Classification failed: ${err}`);
   267ŌåÆ  }
   268ŌåÆ
   269ŌåÆ  // Fallback
   270ŌåÆ  return {
   271ŌåÆ    type: 'work',
   272ŌåÆ    title: prompt.substring(0, 50).replace(/[^a-zA-Z0-9\s]/g, '').trim(),
   273ŌåÆ    effort: 'STANDARD',
   274ŌåÆ    is_new_topic: !hasExistingSession,
   275ŌåÆ  };
   276ŌåÆ}
