   278ŌåÆasync function main() {
   279ŌåÆ  try {
   280ŌåÆ    const input = await readStdinWithTimeout();
   281ŌåÆ    const data: HookInput = JSON.parse(input);
   282ŌåÆ    const prompt = data.prompt || data.user_prompt || '';
   283ŌåÆ    const sessionId = data.session_id || 'unknown';
   284ŌåÆ
   285ŌåÆ    if (!prompt || prompt.length < 2) {
   286ŌåÆ      process.exit(0);
   287ŌåÆ    }
   288ŌåÆ
   289ŌåÆ    if (!existsSync(WORK_DIR)) mkdirSync(WORK_DIR, { recursive: true });
   290ŌåÆ
   291ŌåÆ    let currentWork = readCurrentWork();
   292ŌåÆ    const isExistingSession = currentWork && currentWork.session_id === sessionId;
   293ŌåÆ
   294ŌåÆ    const classification = await classifyPrompt(prompt, !!isExistingSession);
   295ŌåÆ
   296ŌåÆ    // Skip task creation for pure conversational
   297ŌåÆ    if (classification.type === 'conversational' && !classification.is_new_topic) {
   298ŌåÆ      console.error('[AutoWork] Conversational continuation, no new task');
   299ŌåÆ      process.exit(0);
   300ŌåÆ    }
   301ŌåÆ
   302ŌåÆ    if (!isExistingSession) {
