   322ŌåÆ      };
   323ŌåÆ      writeCurrentWork(currentWork);
   324ŌåÆ
   325ŌåÆ      console.error(`[AutoWork] New session with task: ${taskDirName}`);
   326ŌåÆ    } else if (classification.is_new_topic) {
