   328ŌåÆ      const sessionPath = join(WORK_DIR, currentWork!.session_dir);
   329ŌåÆ      const newTaskNumber = currentWork!.task_count + 1;
   330ŌåÆ      const title = classification.title || prompt.substring(0, 50);
   331ŌåÆ
   332ŌåÆ      const taskDirName = createTaskDirectory(
   333ŌåÆ        sessionPath,
   334ŌåÆ        newTaskNumber,
