   192ŌåÆfunction extractCompletionMessage(taskOutput: string): { message: string | null, agentType: string | null } {
   193ŌåÆ  console.error('­¤öŹ DEBUG - Extracting from task output, length:', taskOutput.length);
   194ŌåÆ  console.error('­¤öŹ DEBUG - First 200 chars:', taskOutput.substring(0, 200));
   195ŌåÆ  console.error('­¤öŹ DEBUG - Last 200 chars:', taskOutput.substring(taskOutput.length - 200));
   196ŌåÆ
   197ŌåÆ  // Look for the COMPLETED section in the agent's output
   198ŌåÆ  // Priority: 1) New ­¤ŚŻ’ĖÅ format, 2) Legacy [AGENT:type] format
   199ŌåÆ  const agentPatterns = [
   200ŌåÆ    // NEW FORMAT: ­¤ŚŻ’ĖÅ AgentName: [text] (primary)
   201ŌåÆ    // Captures agent name dynamically from the line
   202ŌåÆ    /­¤ŚŻ’ĖÅ\s*\*{0,2}([\w-]+):?\*{0,2}\s*(.+?)(?:\n|$)/is,
   203ŌåÆ
   204ŌåÆ    // LEGACY FORMAT: ­¤Ä» COMPLETED: [AGENT:type] [text] (backward compatibility)
   205ŌåÆ    // Handle markdown formatting with asterisks - same line
   206ŌåÆ    /\*+­¤Ä»\s*COMPLETED:\*+\s*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   207ŌåÆ    /\*+­¤Ä»\s+COMPLETED:\*+\s*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   208ŌåÆ    // Non-markdown patterns - same line
   209ŌåÆ    /­¤Ä»\s*COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   210ŌåÆ    /COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   211ŌåÆ
   212ŌåÆ    // Multi-line patterns (emoji/COMPLETED on one line, AGENT tag on next)
   213ŌåÆ    /­¤Ä»\s*COMPLETED[\s\n]+\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   214ŌåÆ    /##\s*­¤Ä»\s*COMPLETED[\s\n]+\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   215ŌåÆ    /\*+­¤Ä»\s*COMPLETED\*+[\s\n]+\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   216ŌåÆ
   217ŌåÆ    // Generic pattern for current format
   218ŌåÆ    /­¤Ä».*COMPLETED.*\[AGENT:(\w+[-\w]*)\]\s*(.+?)(?:\n|$)/is,
   219ŌåÆ
   220ŌåÆ    // OLD: Handle legacy "I completed" format (for backward compatibility)
   221ŌåÆ    /\*+­¤Ä»\s*COMPLETED:\*+\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
   222ŌåÆ    /\*+­¤Ä»\s+COMPLETED:\*+\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
   223ŌåÆ    /­¤Ä»\s*COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
   224ŌåÆ    /COMPLETED:\s*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is,
   225ŌåÆ    /\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\.|!|\n|$)/is,
   226ŌåÆ    /­¤Ä».*COMPLETED.*\[AGENT:(\w+[-\w]*)\]\s*I\s+completed\s+(.+?)(?:\n|$)/is
   227ŌåÆ  ];
   228ŌåÆ
   229ŌåÆ  // First try to match agent-specific patterns
   230ŌåÆ  for (const pattern of agentPatterns) {
   231ŌåÆ    const match = taskOutput.match(pattern);
   232ŌåÆ    if (match && match[1] && match[2]) {
   233ŌåÆ      const agentType = match[1].toLowerCase();
   234ŌåÆ      let message = match[2].trim();
   235ŌåÆ
   236ŌåÆ      // Prepend agent name for spoken message
   237ŌåÆ      const agentName = agentType.charAt(0).toUpperCase() + agentType.slice(1);
   238ŌåÆ
   239ŌåÆ      // Intelligent "completed" detection
   240ŌåÆ      // Don't say "completed" for greetings, questions, or status updates
   241ŌåÆ      const isGreeting = /^(hey|hello|hi|greetings|good morning|good afternoon|good evening)/i.test(message);
   242ŌåÆ      const isQuestion = message.includes('?');
   243ŌåÆ      const isStatusUpdate = /(ready to help|online|here|available|standing by|doing (great|well|fine))/i.test(message);
   244ŌåÆ
   245ŌåÆ      const fullMessage = (isGreeting || isQuestion || isStatusUpdate)
   246ŌåÆ        ? message  // Just the message for greetings/questions/status
   247ŌåÆ        : `${agentName} completed ${message}`;  // Prepend "completed" for tasks
   248ŌåÆ
   249ŌåÆ      console.error(`Ō£ģ FOUND AGENT MATCH: [${agentType}] ${fullMessage}`);
   250ŌåÆ
   251ŌåÆ      // Return agent type and message
   252ŌåÆ      return { message: fullMessage, agentType };
   253ŌåÆ    }
   254ŌåÆ  }
   255ŌåÆ
   256ŌåÆ  // Fall back to generic patterns but try to extract agent type
   257ŌåÆ  const genericPatterns = [
   258ŌåÆ    // NEW FORMAT: ­¤ŚŻ’ĖÅ [text] (without specific name - fallback)
   259ŌåÆ    /­¤ŚŻ’ĖÅ\s*(.+?)(?:\n|$)/i,
   260ŌåÆ    // LEGACY FORMAT (backward compatibility)
   261ŌåÆ    // Handle markdown formatting
   262ŌåÆ    /\*+­¤Ä»\s*COMPLETED:\*+\s*(.+?)(?:\n|$)/i,
   263ŌåÆ    /\*+COMPLETED:\*+\s*(.+?)(?:\n|$)/i,
   264ŌåÆ    // Non-markdown patterns
   265ŌåÆ    /­¤Ä»\s*COMPLETED:\s*(.+?)(?:\n|$)/i,
   266ŌåÆ    /COMPLETED:\s*(.+?)(?:\n|$)/i,
   267ŌåÆ    /Sub-agent\s+\w+\s+completed\s+(.+?)(?:\.|!|\n|$)/i,
   268ŌåÆ    /Agent\s+completed\s+(.+?)(?:\.|!|\n|$)/i
   269ŌåÆ  ];
   270ŌåÆ
   271ŌåÆ  for (const pattern of genericPatterns) {
   272ŌåÆ    const match = taskOutput.match(pattern);
   273ŌåÆ    if (match && match[1]) {
   274ŌåÆ      let message = match[1].trim();
   275ŌåÆ
   276ŌåÆ      // Basic cleanup
   277ŌåÆ      message = message.replace(/^(the\s+)?requested\s+task$/i, '');
   278ŌåÆ
   279ŌåÆ      // Only return if it's not a generic message
   280ŌåÆ      if (message &&
   281ŌåÆ          !message.match(/^(the\s+)?requested\s+task$/i) &&
   282ŌåÆ          !message.match(/^task$/i) &&
   283ŌåÆ          message.length > 5) {
   284ŌåÆ
   285ŌåÆ        // Try to detect agent type from context
   286ŌåÆ        let agentType = null;
   287ŌåÆ        const agentMatch = taskOutput.match(/Sub-agent\s+(\w+)\s+completed/i);
   288ŌåÆ        if (agentMatch) {
   289ŌåÆ          agentType = agentMatch[1].toLowerCase();
   290ŌåÆ        }
   291ŌåÆ
   292ŌåÆ        return { message, agentType };
   293ŌåÆ      }
   294ŌåÆ    }
   295ŌåÆ  }
   296ŌåÆ
   297ŌåÆ  return { message: null, agentType: null };
   298ŌåÆ}
