   445ŌåÆ// UOCS: Capture agent output to history directory
   446ŌåÆasync function captureAgentOutput(
   447ŌåÆ  agentType: string,
   448ŌåÆ  completionMessage: string,
   449ŌåÆ  taskOutput: string,
   450ŌåÆ  transcriptPath: string
   451ŌåÆ) {
   452ŌåÆ  const { writeFileSync, mkdirSync, existsSync } = require('fs');
   453ŌåÆ  const { join } = require('path');
   454ŌåÆ  const { homedir } = require('os');
   455ŌåÆ
   456ŌåÆ  const MEMORY_DIR = paiPath('MEMORY');
   457ŌåÆ
   458ŌåÆ  // Generate timestamp for filename (PST)
   459ŌåÆ  const pstTimestamp = getPSTTimestamp();
   460ŌåÆ  const timestamp = pstTimestamp
   461ŌåÆ    .replace(/ PST$/, '')
   462ŌåÆ    .replace(/:/g, '')
   463ŌåÆ    .replace(/ /, '-'); // YYYY-MM-DD-HHMMSS
   464ŌåÆ
   465ŌåÆ  const yearMonth = timestamp.substring(0, 7); // YYYY-MM
   466ŌåÆ
   467ŌåÆ  // Infer capture type from agent type
   468ŌåÆ  // All agent outputs go to RESEARCH for simplicity (consolidated structure)
   469ŌåÆ  let captureType = 'RESEARCH';
   470ŌåÆ  const category = 'RESEARCH';
   471ŌåÆ
   472ŌåÆ  if (agentType === 'researcher' || agentType.includes('researcher')) {
   473ŌåÆ    captureType = 'RESEARCH';
   474ŌåÆ  } else if (agentType === 'architect') {
   475ŌåÆ    captureType = 'DECISION';
   476ŌåÆ  } else if (agentType === 'engineer') {
   477ŌåÆ    captureType = 'IMPLEMENTATION';
   478ŌåÆ  } else if (agentType === 'designer') {
   479ŌåÆ    captureType = 'DESIGN';
   480ŌåÆ  } else if (agentType === 'pentester') {
   481ŌåÆ    captureType = 'SECURITY';
   482ŌåÆ  } else if (agentType === 'intern') {
   483ŌåÆ    captureType = 'RESEARCH';
   484ŌåÆ  }
   485ŌåÆ
   486ŌåÆ  // Generate description from completion message (kebab-case, max 60 chars)
   487ŌåÆ  const description = completionMessage
   488ŌåÆ    .toLowerCase()
   489ŌåÆ    .replace(/^(architect|engineer|designer|researcher|pentester|intern)\s+completed\s+/i, '')
   490ŌåÆ    .replace(/[^a-z0-9]+/g, '-')
   491ŌåÆ    .replace(/^-|-$/g, '')
   492ŌåÆ    .substring(0, 60);
   493ŌåÆ
   494ŌåÆ  // Generate filename
   495ŌåÆ  const filename = `${timestamp}_AGENT-${agentType}_${captureType}_${description}.md`;
   496ŌåÆ
   497ŌåÆ  // Ensure directory exists
   498ŌåÆ  const outputDir = join(MEMORY_DIR, category, yearMonth);
   499ŌåÆ  if (!existsSync(outputDir)) {
   500ŌåÆ    mkdirSync(outputDir, { recursive: true });
   501ŌåÆ  }
   502ŌåÆ
   503ŌåÆ  // Format document
   504ŌåÆ  const fullTimestamp = getPSTTimestamp();
   505ŌåÆ  const document = `---
   506ŌåÆcapture_type: ${captureType}
   507ŌåÆtimestamp: ${fullTimestamp}
   508ŌåÆexecutor: ${agentType}
   509ŌåÆagent_completion: ${completionMessage}
   510ŌåÆ---
   511ŌåÆ
   512ŌåÆ# ${captureType}: ${completionMessage}
   513ŌåÆ
   514ŌåÆ**Agent:** ${agentType}
   515ŌåÆ**Completed:** ${timestamp.replace(/-/g, ':').substring(0, 19)}
   516ŌåÆ
   517ŌåÆ---
   518ŌåÆ
   519ŌåÆ## Agent Output
   520ŌåÆ
   521ŌåÆ${taskOutput}
   522ŌåÆ
   523ŌåÆ---
   524ŌåÆ
   525ŌåÆ## Metadata
   526ŌåÆ
   527ŌåÆ**Transcript:** \`${transcriptPath}\`
   528ŌåÆ**Captured:** ${fullTimestamp}
   529ŌåÆ
   530ŌåÆ---
   531ŌåÆ
   532ŌåÆ*This output was automatically captured by UOCS SubagentStop hook.*
   533ŌåÆ`;
   534ŌåÆ
   535ŌåÆ  // Write file
   536ŌåÆ  const filePath = join(outputDir, filename);
   537ŌåÆ  writeFileSync(filePath, document);
   538ŌåÆ
   539ŌåÆ  console.log(`­¤ōØ UOCS: Captured agent output to ${category}/${yearMonth}/${filename}`);
   540ŌåÆ}
