   318ŌåÆ/**
   319ŌåÆ * Handle response capture with pre-parsed transcript data.
   320ŌåÆ */
   321ŌåÆexport async function handleCapture(parsed: ParsedTranscript, hookInput: HookInput): Promise<void> {
   322ŌåÆ  const { lastMessage, structured, plainCompletion } = parsed;
   323ŌåÆ
