   335ŌåÆ  }
   336ŌåÆ
   337ŌåÆ  const hasError = lastMessage && (
   338ŌåÆ    /error|failed|exception|crash/i.test(lastMessage) &&
   339ŌåÆ    /­¤ōŖ\s*STATUS:.*(?:error|failed|broken)/i.test(lastMessage)
