     2ŌåÆ/**
     3ŌåÆ * RebuildSkill.ts - Auto-rebuild CORE SKILL.md from Components
     4ŌåÆ *
     5ŌåÆ * PURPOSE:
     6ŌåÆ * Automatically rebuilds SKILL.md from Components/ after every response.
     7ŌåÆ * Ensures SKILL.md stays current if components were edited during the session.
     8ŌåÆ *
     9ŌåÆ * TRIGGER: Stop event (via StopOrchestrator)
    10ŌåÆ *
    11ŌåÆ * BEHAVIOR:
    12ŌåÆ * - Checks if any Component file is newer than SKILL.md
    13ŌåÆ * - If yes, runs BuildSkill.ts to regenerate SKILL.md
    14ŌåÆ * - Logs rebuild status to stderr
    15ŌåÆ *
    16ŌåÆ * DESIGN RATIONALE:
    17ŌåÆ * - Rebuild on session END (not START) keeps LoadContext fast
    18ŌåÆ * - Components are source of truth, SKILL.md is generated artifact
    19ŌåÆ * - No manual `bun BuildSkill.ts` needed - happens automatically
    20ŌåÆ */
    21ŌåÆ
    22ŌåÆimport { statSync, readdirSync } from 'fs';
    23ŌåÆimport { join } from 'path';
    24ŌåÆimport { spawnSync } from 'child_process';
    25ŌåÆ
    26ŌåÆexport async function handleRebuildSkill(): Promise<void> {
    27ŌåÆ  const CORE_DIR = join(process.env.HOME!, '.claude/skills/PAI');
    28ŌåÆ  const COMPONENTS_DIR = join(CORE_DIR, 'Components');
    29ŌåÆ  const SKILL_MD = join(CORE_DIR, 'SKILL.md');
    30ŌåÆ  const BUILD_SCRIPT = join(CORE_DIR, 'Tools/CreateDynamicCore.ts');
    31ŌåÆ
    32ŌåÆ  try {
    33ŌåÆ    // Check if SKILL.md exists
    34ŌåÆ    let skillStat;
    35ŌåÆ    try {
    36ŌåÆ      skillStat = statSync(SKILL_MD);
    37ŌåÆ    } catch {
    38ŌåÆ      // SKILL.md doesn't exist - rebuild needed
    39ŌåÆ      console.error('[RebuildSkill] SKILL.md missing - rebuilding');
    40ŌåÆ      rebuild(BUILD_SCRIPT);
    41ŌåÆ      return;
    42ŌåÆ    }
    43ŌåÆ
    44ŌåÆ    // Check if any component is newer than SKILL.md
    45ŌåÆ    const components = readdirSync(COMPONENTS_DIR).filter(f => f.endsWith('.md'));
    46ŌåÆ    const anyNewer = components.some(file => {
    47ŌåÆ      const componentPath = join(COMPONENTS_DIR, file);
    48ŌåÆ      const componentStat = statSync(componentPath);
    49ŌåÆ      return componentStat.mtimeMs > skillStat.mtimeMs;
    50ŌåÆ    });
    51ŌåÆ
    52ŌåÆ    if (anyNewer) {
    53ŌåÆ      console.error('[RebuildSkill] Components modified - rebuilding SKILL.md');
    54ŌåÆ      rebuild(BUILD_SCRIPT);
    55ŌåÆ    } else {
    56ŌåÆ      console.error('[RebuildSkill] SKILL.md is current - no rebuild needed');
    57ŌåÆ    }
    58ŌåÆ  } catch (error) {
    59ŌåÆ    console.error('[RebuildSkill] Error checking/rebuilding:', error);
    60ŌåÆ  }
    61ŌåÆ}
    62ŌåÆ
    63ŌåÆfunction rebuild(buildScript: string): void {
    64ŌåÆ  const result = spawnSync('bun', [buildScript], {
    65ŌåÆ    cwd: join(process.env.HOME!, '.claude/skills/PAI'),
    66ŌåÆ    encoding: 'utf-8',
    67ŌåÆ  });
    68ŌåÆ
    69ŌåÆ  if (result.error) {
    70ŌåÆ    console.error('[RebuildSkill] Build failed:', result.error);
    71ŌåÆ  } else {
    72ŌåÆ    console.error('[RebuildSkill]', result.stdout?.trim() || 'Build completed');
    73ŌåÆ  }
    74ŌåÆ}
