   426ŌåÆ  // Major: new skills/workflows, architectural decisions
   427ŌåÆ  if (hasNewFiles && (hasStructural || hasPhilosophical)) {
   428ŌåÆ    return 'major';
   429ŌåÆ  }
   430ŌåÆ  if (hasCoreSystem || (categories.size >= 3)) {
   431ŌåÆ    return 'major';
   432ŌåÆ  }
   433ŌåÆ  if (hasHooks && count >= 3) {
   434ŌåÆ    return 'major';
   435ŌåÆ  }
   436ŌåÆ
   437ŌåÆ  // Moderate: multi-file updates, small features
   438ŌåÆ  if (count >= 3 || categories.size >= 2) {
   439ŌåÆ    return 'moderate';
   440ŌåÆ  }
   441ŌåÆ  if (hasSkills && count >= 2) {
   442ŌåÆ    return 'moderate';
   443ŌåÆ  }
   444ŌåÆ
   445ŌåÆ  // Minor: single file doc updates
   446ŌåÆ  if (count === 1 && !hasStructural && !hasPhilosophical) {
   447ŌåÆ    return 'minor';
   448ŌåÆ  }
   449ŌåÆ
   450ŌåÆ  // Trivial: only if very small doc changes
