   458ŌåÆ/**
   459ŌåÆ * Determine the change type based on affected files.
   460ŌåÆ */
   461ŌåÆexport function inferChangeType(changes: FileChange[]): ChangeType {
   462ŌåÆ  const categories = changes.map(c => c.category).filter(Boolean);
   463ŌåÆ  const uniqueCategories = new Set(categories);
   464ŌåÆ
   465ŌåÆ  // Multi-area if touching 3+ categories
   466ŌåÆ  if (uniqueCategories.size >= 3) {
   467ŌåÆ    return 'multi_area';
   468ŌåÆ  }
   469ŌåÆ
   470ŌåÆ  // Single category cases
   471ŌåÆ  if (uniqueCategories.size === 1) {
   472ŌåÆ    const cat = [...uniqueCategories][0];
   473ŌåÆ    switch (cat) {
   474ŌåÆ      case 'skill': return changes.some(c => c.isStructural) ? 'structure_change' : 'skill_update';
   475ŌåÆ      case 'hook': return 'hook_update';
   476ŌåÆ      case 'workflow': return 'workflow_update';
   477ŌåÆ      case 'config': return 'config_update';
   478ŌåÆ      case 'core-system': return 'structure_change';
   479ŌåÆ      case 'documentation': return 'doc_update';
   480ŌåÆ      default: return 'skill_update';
   481ŌåÆ    }
   482ŌåÆ  }
   483ŌåÆ
   484ŌåÆ  // Two categories - pick the more significant one
   485ŌåÆ  if (uniqueCategories.has('hook')) return 'hook_update';
   486ŌåÆ  if (uniqueCategories.has('skill')) return 'skill_update';
   487ŌåÆ  if (uniqueCategories.has('workflow')) return 'workflow_update';
   488ŌåÆ  if (uniqueCategories.has('config')) return 'config_update';
   489ŌåÆ
   490ŌåÆ  return 'multi_area';
   491ŌåÆ}
