   493ŌåÆ/**
   494ŌåÆ * Generate a descriptive 4-8 word title based on the changes.
   495ŌåÆ */
   496ŌåÆexport function generateDescriptiveTitle(changes: FileChange[]): string {
   497ŌåÆ  const paths = changes.map(c => c.path);
   498ŌåÆ
   499ŌåÆ  // Extract skill names
   500ŌåÆ  const skillNames = new Set<string>();
   501ŌåÆ  for (const p of paths) {
   502ŌåÆ    const match = p.match(/skills\/([^/]+)\//);
   503ŌåÆ    if (match && match[1] !== 'PAI') skillNames.add(match[1]);
   504ŌåÆ  }
   505ŌåÆ
   506ŌåÆ  // Detect file types
   507ŌåÆ  const hasSkillMd = paths.some(p => p.endsWith('SKILL.md'));
