   509ŌåÆ  const hasTools = paths.some(p => p.includes('/Tools/') && p.endsWith('.ts'));
   510ŌåÆ  const hasHooks = paths.some(p => p.includes('hooks/'));
   511ŌåÆ  const hasConfig = paths.some(p => p.endsWith('settings.json'));
   512ŌåÆ  const hasCoreSystem = paths.some(p => p.includes('PAI/SYSTEM/'));
   513ŌåÆ  const hasCoreUser = paths.some(p => p.includes('PAI/USER/'));
   514ŌåÆ
   515ŌåÆ  let title = '';
   516ŌåÆ
   517ŌåÆ  // Single skill update
   518ŌåÆ  if (skillNames.size === 1) {
   519ŌåÆ    const skill = [...skillNames][0];
   520ŌåÆ    if (hasSkillMd) {
   521ŌåÆ      title = `${skill} Skill Definition Update`;
   522ŌåÆ    } else if (hasWorkflows) {
   523ŌåÆ      const workflowNames = paths
   524ŌåÆ        .filter(p => p.includes('/Workflows/'))
   525ŌåÆ        .map(p => basename(p, '.md'));
   526ŌåÆ      if (workflowNames.length === 1) {
   527ŌåÆ        title = `${skill} ${workflowNames[0]} Workflow Update`;
   528ŌåÆ      } else {
   529ŌåÆ        title = `${skill} Workflows Updated`;
   530ŌåÆ      }
   531ŌåÆ    } else if (hasTools) {
   532ŌåÆ      const toolNames = paths
   533ŌåÆ        .filter(p => p.includes('/Tools/'))
   534ŌåÆ        .map(p => basename(p, '.ts'));
   535ŌåÆ      if (toolNames.length === 1) {
   536ŌåÆ        title = `${skill} ${toolNames[0]} Tool Update`;
   537ŌåÆ      } else {
   538ŌåÆ        title = `${skill} Tools Updated`;
   539ŌåÆ      }
   540ŌåÆ    } else {
   541ŌåÆ      title = `${skill} Skill Files Updated`;
   542ŌåÆ    }
   543ŌåÆ  }
   544ŌåÆ  // Multiple skills
   545ŌåÆ  else if (skillNames.size > 1 && skillNames.size <= 3) {
   546ŌåÆ    const skills = [...skillNames].slice(0, 3).join(' and ');
   547ŌåÆ    title = `${skills} Skills Updated`;
   548ŌåÆ  }
   549ŌåÆ  // Hook changes
   550ŌåÆ  else if (hasHooks) {
   551ŌåÆ    const hookNames = paths
   552ŌåÆ      .filter(p => p.includes('hooks/'))
   553ŌåÆ      .map(p => basename(p, '.ts').replace('.hook', ''));
   554ŌåÆ    if (hookNames.length === 1) {
   555ŌåÆ      title = `${hookNames[0]} Hook Updated`;
   556ŌåÆ    } else if (hookNames.length <= 3) {
   557ŌåÆ      title = `${hookNames.slice(0, 3).join(', ')} Hooks Updated`;
   558ŌåÆ    } else {
   559ŌåÆ      title = `Hook System Updates`;
   560ŌåÆ    }
   561ŌåÆ  }
   562ŌåÆ  // Config changes
   563ŌåÆ  else if (hasConfig) {
   564ŌåÆ    title = 'System Configuration Updated';
   565ŌåÆ  }
   566ŌåÆ  // Core system changes
   567ŌåÆ  else if (hasCoreSystem) {
   568ŌåÆ    const docNames = paths
   569ŌåÆ      .filter(p => p.includes('PAI/SYSTEM/'))
   570ŌåÆ      .map(p => basename(p, '.md'));
   571ŌåÆ    if (docNames.length === 1) {
   572ŌåÆ      title = `${docNames[0]} Documentation Updated`;
   573ŌåÆ    } else {
   574ŌåÆ      title = 'PAI System Documentation Updated';
   575ŌåÆ    }
   576ŌåÆ  }
   577ŌåÆ  // Core user changes
   578ŌåÆ  else if (hasCoreUser) {
   579ŌåÆ    const docNames = paths
   580ŌåÆ      .filter(p => p.includes('PAI/USER/'))
   581ŌåÆ      .map(p => basename(p, '.md'));
   582ŌåÆ    if (docNames.length === 1) {
   583ŌåÆ      title = `${docNames[0]} User Config Updated`;
   584ŌåÆ    } else {
   585ŌåÆ      title = 'User Configuration Updated';
   586ŌåÆ    }
   587ŌåÆ  }
   588ŌåÆ  // Fallback
   589ŌåÆ  else {
   590ŌåÆ    const categories = new Set(changes.map(c => c.category).filter(Boolean));
   591ŌåÆ    if (categories.size === 1) {
   592ŌåÆ      const cat = [...categories][0];
   593ŌåÆ      title = `${capitalize(cat || 'System')} Updates Applied`;
   594ŌåÆ    } else {
   595ŌåÆ      title = 'Multi-Area System Updates Applied';
   596ŌåÆ    }
   597ŌåÆ  }
   598ŌåÆ
   599ŌåÆ  // Ensure 4-8 words
   600ŌåÆ  const words = title.split(/\s+/);
   601ŌåÆ  if (words.length < 4) {
   602ŌåÆ    title = `PAI ${title}`;
   603ŌåÆ  } else if (words.length > 8) {
   604ŌåÆ    title = words.slice(0, 8).join(' ');
   605ŌåÆ  }
   606ŌåÆ
   607ŌåÆ  return title;
   608ŌåÆ}
   609ŌåÆ
   610ŌåÆfunction capitalize(s: string): string {
   611ŌåÆ  return s.charAt(0).toUpperCase() + s.slice(1);
   612ŌåÆ}
