    99ŌåÆ/**
   100ŌåÆ * Expand ${VAR} patterns in a string using environment variables
   101ŌåÆ */
   102ŌåÆfunction expandEnvVars(content: string): string {
   103ŌåÆ  return content.replace(/\$\{(\w+)\}/g, (_, key) => process.env[key] || '');
   104ŌåÆ}
