   106ŌåÆ/**
   107ŌåÆ * Load notification config from settings.json
   108ŌåÆ */
   109ŌåÆexport function getNotificationConfig(): NotificationConfig {
   110ŌåÆ  try {
   111ŌåÆ    const paiDir = process.env.PAI_DIR || join(homedir(), '.claude');
   112ŌåÆ    const settingsPath = join(paiDir, 'settings.json');
   113ŌåÆ
   114ŌåÆ    if (existsSync(settingsPath)) {
   115ŌåÆ      const rawContent = readFileSync(settingsPath, 'utf-8');
   116ŌåÆ      const expandedContent = expandEnvVars(rawContent);
   117ŌåÆ      const settings = JSON.parse(expandedContent);
   118ŌåÆ      if (settings.notifications) {
   119ŌåÆ        return {
   120ŌåÆ          ...DEFAULT_CONFIG,
   121ŌåÆ          ...settings.notifications,
   122ŌåÆ          ntfy: { ...DEFAULT_CONFIG.ntfy, ...settings.notifications?.ntfy },
   123ŌåÆ          discord: { ...DEFAULT_CONFIG.discord, ...settings.notifications?.discord },
   124ŌåÆ          twilio: { ...DEFAULT_CONFIG.twilio, ...settings.notifications?.twilio },
   125ŌåÆ          thresholds: { ...DEFAULT_CONFIG.thresholds, ...settings.notifications?.thresholds },
   126ŌåÆ          routing: { ...DEFAULT_CONFIG.routing, ...settings.notifications?.routing }
   127ŌåÆ        };
   128ŌåÆ      }
   129ŌåÆ    }
   130ŌåÆ  } catch (error) {
   131ŌåÆ    // Fail gracefully, use defaults
   132ŌåÆ    console.error('Failed to load notification config:', error);
   133ŌåÆ  }
   134ŌåÆ
   135ŌåÆ  return DEFAULT_CONFIG;
   136ŌåÆ}
