   184ŌåÆ/**
   185ŌåÆ * Send push notification via ntfy.sh
   186ŌåÆ */
   187ŌåÆexport async function sendPush(
   188ŌåÆ  message: string,
   189ŌåÆ  options: NotificationOptions = {}
   190ŌåÆ): Promise<boolean> {
   191ŌåÆ  const config = getNotificationConfig();
   192ŌåÆ
   193ŌåÆ  if (!config.ntfy.enabled || !config.ntfy.topic) {
   194ŌåÆ    return false;
   195ŌåÆ  }
   196ŌåÆ
   197ŌåÆ  try {
   198ŌåÆ    const url = `https://${config.ntfy.server}/${config.ntfy.topic}`;
   199ŌåÆ
   200ŌåÆ    const headers: Record<string, string> = {
   201ŌåÆ      'Content-Type': 'text/plain',
   202ŌåÆ    };
   203ŌåÆ
   204ŌåÆ    if (options.title) {
   205ŌåÆ      headers['Title'] = options.title;
   206ŌåÆ    }
   207ŌåÆ
   208ŌåÆ    if (options.priority) {
   209ŌåÆ      // ntfy uses numeric priorities: 1 (min) to 5 (max)
   210ŌåÆ      const priorityMap: Record<NotificationPriority, string> = {
   211ŌåÆ        'min': '1',
   212ŌåÆ        'low': '2',
   213ŌåÆ        'default': '3',
   214ŌåÆ        'high': '4',
   215ŌåÆ        'urgent': '5'
   216ŌåÆ      };
   217ŌåÆ      headers['Priority'] = priorityMap[options.priority] || '3';
   218ŌåÆ    }
   219ŌåÆ
   220ŌåÆ    if (options.tags && options.tags.length > 0) {
   221ŌåÆ      headers['Tags'] = options.tags.join(',');
   222ŌåÆ    }
   223ŌåÆ
   224ŌåÆ    if (options.click) {
   225ŌåÆ      headers['Click'] = options.click;
   226ŌåÆ    }
   227ŌåÆ
   228ŌåÆ    if (options.actions && options.actions.length > 0) {
   229ŌåÆ      headers['Actions'] = options.actions
   230ŌåÆ        .map(a => `${a.action}, ${a.label}, ${a.url}`)
   231ŌåÆ        .join('; ');
   232ŌåÆ    }
   233ŌåÆ
   234ŌåÆ    const response = await fetch(url, {
   235ŌåÆ      method: 'POST',
   236ŌåÆ      headers,
   237ŌåÆ      body: message
   238ŌåÆ    });
   239ŌåÆ
   240ŌåÆ    return response.ok;
   241ŌåÆ  } catch (error) {
   242ŌåÆ    // Fail silently - don't block hook execution
   243ŌåÆ    console.error('ntfy send failed:', error);
   244ŌåÆ    return false;
   245ŌåÆ  }
   246ŌåÆ}
