   282ŌåÆ
   283ŌåÆ    const response = await fetch(config.discord.webhook, {
   284ŌåÆ      method: 'POST',
   285ŌåÆ      headers: { 'Content-Type': 'application/json' },
   286ŌåÆ      body: JSON.stringify(payload)
