   330ŌåÆ  if (!config.twilio.enabled || !config.twilio.toNumber) {
   331ŌåÆ    return false;
   332ŌåÆ  }
   333ŌåÆ
   334ŌåÆ  const accountSid = process.env.TWILIO_ACCOUNT_SID;
   335ŌåÆ  const authToken = process.env.TWILIO_AUTH_TOKEN;
   336ŌåÆ
   337ŌåÆ  if (!accountSid || !authToken) {
   338ŌåÆ    console.error('Twilio credentials not found in environment');
   339ŌåÆ    return false;
   340ŌåÆ  }
