   342ŌåÆ  try {
   343ŌåÆ    const fromNumber = process.env.TWILIO_FROM_NUMBER;
   344ŌåÆ    if (!fromNumber) {
   345ŌåÆ      console.error('TWILIO_FROM_NUMBER not set in environment');
   346ŌåÆ      return false;
   347ŌåÆ    }
