   349ŌåÆ    const body = `[${DA_NAME}] ${message}`.substring(0, 160); // SMS limit
   350ŌåÆ
   351ŌåÆ    // Use curl for reliability
   352ŌåÆ    const proc = Bun.spawn([
   353ŌåÆ      'curl', '-s', '-X', 'POST',
   354ŌåÆ      `https://api.twilio.com/2010-04-01/Accounts/${accountSid}/Messages.json`,
   355ŌåÆ      '-u', `${accountSid}:${authToken}`,
   356ŌåÆ      '-d', `To=${config.twilio.toNumber}`,
   357ŌåÆ      '-d', `From=${fromNumber}`,
   358ŌåÆ      '-d', `Body=${body}`
