   362ŌåÆ    return proc.exitCode === 0;
   363ŌåÆ  } catch (error) {
   364ŌåÆ    console.error('SMS send failed:', error);
   365ŌåÆ    return false;
   366ŌåÆ  }
   367ŌåÆ}
