   370ŌåÆ// Smart Router
   371ŌåÆ// ============================================================================
   372ŌåÆ
   373ŌåÆ/**
   374ŌåÆ * Send notification through appropriate channels based on event type
   375ŌåÆ * This is the main entry point for notifications
   376ŌåÆ */
   377ŌåÆexport async function notify(
   378ŌåÆ  event: NotificationEvent,
   379ŌåÆ  message: string,
   380ŌåÆ  options: NotificationOptions = {}
