   382ŌåÆ  const config = getNotificationConfig();
   383ŌåÆ  const channels = config.routing[event] || [];
   384ŌåÆ
   385ŌåÆ  // Fire all notifications in parallel, don't wait for completion
   386ŌåÆ  const promises: Promise<boolean>[] = [];
   387ŌåÆ
   388ŌåÆ  for (const channel of channels) {
   389ŌåÆ    switch (channel) {
   390ŌåÆ      case 'ntfy':
   391ŌåÆ        promises.push(sendPush(message, {
   392ŌåÆ          title: options.title || getDefaultTitle(event),
   393ŌåÆ          priority: options.priority || getDefaultPriority(event),
   394ŌåÆ          tags: options.tags || getDefaultTags(event),
   395ŌåÆ          ...options
   396ŌåÆ        }));
   397ŌåÆ        break;
   398ŌåÆ
   399ŌåÆ      case 'discord':
   400ŌåÆ        promises.push(sendDiscord(message, {
   401ŌåÆ          title: options.title || getDefaultTitle(event),
   402ŌåÆ          color: getDiscordColor(event)
   403ŌåÆ        }));
   404ŌåÆ        break;
   405ŌåÆ
   406ŌåÆ      case 'desktop':
   407ŌåÆ        promises.push(sendDesktop(
   408ŌåÆ          options.title || getDefaultTitle(event),
   409ŌåÆ          message,
   410ŌåÆ          { sound: event === 'error' || event === 'security' ? 'Basso' : 'Glass' }
   411ŌåÆ        ));
   412ŌåÆ        break;
   413ŌåÆ
   414ŌåÆ      case 'sms':
   415ŌåÆ        promises.push(sendSMS(message));
   416ŌåÆ        break;
   417ŌåÆ    }
   418ŌåÆ  }
   419ŌåÆ
   420ŌåÆ  // Fire and forget - don't await
   421ŌåÆ  Promise.all(promises).catch(() => {
   422ŌåÆ    // Silently ignore failures
   423ŌåÆ  });
   424ŌåÆ}
