     2ŌåÆ/**
     3ŌåÆ * Metadata Extraction Library for UOCS Enhancement
     4ŌåÆ *
     5ŌåÆ * Extracts agent instance IDs, parent-child relationships, and session info
     6ŌåÆ * from Task tool calls and other tool inputs.
     7ŌåÆ *
     8ŌåÆ * Design Philosophy: Optional extraction with graceful fallbacks
     9ŌåÆ * - If instance IDs are present in descriptions/prompts, extract them
    10ŌåÆ * - If not present, fall back to agent type only
    11ŌåÆ * - Never fail - always return usable metadata
    12ŌåÆ */
    13ŌåÆ
    14ŌåÆexport interface AgentInstanceMetadata {
    15ŌåÆ  agent_instance_id?: string;      // "perplexity-researcher-1" (full ID)
    16ŌåÆ  agent_type?: string;              // "perplexity-researcher" (base type)
    17ŌåÆ  instance_number?: number;         // 1 (sequence number)
    18ŌåÆ  parent_session_id?: string;       // Session that spawned this agent
    19ŌåÆ  parent_task_id?: string;          // Task ID that spawned this agent
    20ŌåÆ}
    21ŌåÆ
    22ŌåÆ/**
    23ŌåÆ * Extract agent instance ID from Task tool input
    24ŌåÆ *
    25ŌåÆ * Looks for patterns in priority order:
    26ŌåÆ * 1. [agent-type-N] in description (e.g., "Research topic [perplexity-researcher-1]")
    27ŌåÆ * 2. [AGENT_INSTANCE: agent-type-N] in prompt
    28ŌåÆ * 3. subagent_type field (fallback to just type, no instance number)
    29ŌåÆ *
    30ŌåÆ * @param toolInput The tool input object from PreToolUse/PostToolUse hooks
    31ŌåÆ * @param description Optional description field from tool input
    32ŌåÆ * @returns Metadata object with extracted information
    33ŌåÆ */
    34ŌåÆexport function extractAgentInstanceId(
    35ŌåÆ  toolInput: any,
    36ŌåÆ  description?: string
    37ŌåÆ): AgentInstanceMetadata {
    38ŌåÆ  const result: AgentInstanceMetadata = {};
    39ŌåÆ
    40ŌåÆ  // Strategy 1: Extract from description [agent-type-N]
    41ŌåÆ  // Example: "Research consumer complaints [perplexity-researcher-1]"
    42ŌåÆ  if (description) {
    43ŌåÆ    const descMatch = description.match(/\[([a-z-]+-researcher)-(\d+)\]/);
    44ŌåÆ    if (descMatch) {
    45ŌåÆ      result.agent_type = descMatch[1];
    46ŌåÆ      result.instance_number = parseInt(descMatch[2], 10);
    47ŌåÆ      result.agent_instance_id = `${result.agent_type}-${result.instance_number}`;
    48ŌåÆ    }
    49ŌåÆ  }
    50ŌåÆ
    51ŌåÆ  // Strategy 2: Extract from prompt [AGENT_INSTANCE: ...]
    52ŌåÆ  // Example: "[AGENT_INSTANCE: perplexity-researcher-1]"
    53ŌåÆ  if (!result.agent_instance_id && toolInput?.prompt && typeof toolInput.prompt === 'string') {
    54ŌåÆ    const promptMatch = toolInput.prompt.match(/\[AGENT_INSTANCE:\s*([^\]]+)\]/);
    55ŌåÆ    if (promptMatch) {
    56ŌåÆ      result.agent_instance_id = promptMatch[1].trim();
    57ŌåÆ
    58ŌåÆ      // Parse agent type and instance number from ID
    59ŌåÆ      const parts = result.agent_instance_id.match(/^([a-z-]+)-(\d+)$/);
    60ŌåÆ      if (parts) {
    61ŌåÆ        result.agent_type = parts[1];
    62ŌåÆ        result.instance_number = parseInt(parts[2], 10);
    63ŌåÆ      }
    64ŌåÆ    }
    65ŌåÆ  }
    66ŌåÆ
    67ŌåÆ  // Strategy 3: Extract parent session from prompt
    68ŌåÆ  // Example: "[PARENT_SESSION: b7062b5a-03d3-4168-9555-a748e0b2efa3]"
    69ŌåÆ  if (toolInput?.prompt && typeof toolInput.prompt === 'string') {
    70ŌåÆ    const parentSessionMatch = toolInput.prompt.match(/\[PARENT_SESSION:\s*([^\]]+)\]/);
    71ŌåÆ    if (parentSessionMatch) {
    72ŌåÆ      result.parent_session_id = parentSessionMatch[1].trim();
    73ŌåÆ    }
    74ŌåÆ
    75ŌåÆ    // Extract parent task from prompt
    76ŌåÆ    // Example: "[PARENT_TASK: research_1731445892345]"
    77ŌåÆ    const parentTaskMatch = toolInput.prompt.match(/\[PARENT_TASK:\s*([^\]]+)\]/);
    78ŌåÆ    if (parentTaskMatch) {
    79ŌåÆ      result.parent_task_id = parentTaskMatch[1].trim();
    80ŌåÆ    }
    81ŌåÆ  }
    82ŌåÆ
    83ŌåÆ  // Strategy 4: Fallback to subagent_type if available (no instance number)
    84ŌåÆ  // This ensures we at least capture the agent type even without instance IDs
    85ŌåÆ  if (!result.agent_type && toolInput?.subagent_type) {
    86ŌåÆ    result.agent_type = toolInput.subagent_type;
    87ŌåÆ  }
    88ŌåÆ
    89ŌåÆ  return result;
    90ŌåÆ}
    91ŌåÆ
    92ŌåÆ/**
    93ŌåÆ * Enrich event with agent metadata
    94ŌåÆ *
    95ŌåÆ * Takes a base event object and adds agent instance metadata to it.
    96ŌåÆ * Returns a new object with merged metadata.
    97ŌåÆ *
    98ŌåÆ * @param event Base event object (from PreToolUse/PostToolUse)
    99ŌåÆ * @param toolInput Tool input object
   100ŌåÆ * @param description Optional description field
   101ŌåÆ * @returns Enriched event with agent metadata
   102ŌåÆ */
   103ŌåÆexport function enrichEventWithAgentMetadata(
   104ŌåÆ  event: any,
   105ŌåÆ  toolInput: any,
   106ŌåÆ  description?: string
   107ŌåÆ): any {
   108ŌåÆ  const metadata = extractAgentInstanceId(toolInput, description);
   109ŌåÆ
   110ŌåÆ  // Only add fields that have values (keep events clean)
   111ŌåÆ  const enrichedEvent = { ...event };
   112ŌåÆ
   113ŌåÆ  if (metadata.agent_instance_id) {
   114ŌåÆ    enrichedEvent.agent_instance_id = metadata.agent_instance_id;
   115ŌåÆ  }
   116ŌåÆ
   117ŌåÆ  if (metadata.agent_type) {
   118ŌåÆ    enrichedEvent.agent_type = metadata.agent_type;
   119ŌåÆ  }
   120ŌåÆ
   121ŌåÆ  if (metadata.instance_number !== undefined) {
   122ŌåÆ    enrichedEvent.instance_number = metadata.instance_number;
   123ŌåÆ  }
   124ŌåÆ
   125ŌåÆ  if (metadata.parent_session_id) {
   126ŌåÆ    enrichedEvent.parent_session_id = metadata.parent_session_id;
   127ŌåÆ  }
   128ŌåÆ
   129ŌåÆ  if (metadata.parent_task_id) {
   130ŌåÆ    enrichedEvent.parent_task_id = metadata.parent_task_id;
   131ŌåÆ  }
   132ŌåÆ
   133ŌåÆ  return enrichedEvent;
   134ŌåÆ}
