   142ŌåÆ */
   143ŌåÆexport function isAgentSpawningCall(toolName: string, toolInput: any): boolean {
   144ŌåÆ  return toolName === 'Task' && toolInput?.subagent_type !== undefined;
   145ŌåÆ}
